def max_bytes_from_mb(max_mb: float | int | str | None, default_mb: int = DEFAULT_MAX_MB) -> int:
    if max_mb is None or max_mb == "":
        return default_mb * 1024 * 1024
    value = float(max_mb)
    if value <= 0 or value > 25:
        raise ValueError("Max size must be between 0 and 25 MB.")
    return int(value * 1024 * 1024)

