def _encode_png_with_budget(raster: Raster, max_bytes: int) -> bytes:
    best = encode_png(raster, compression_level=9)
    for level in range(8, -1, -1):
        candidate = encode_png(raster, compression_level=level)
        best = candidate
        if len(candidate) <= max_bytes:
            return candidate
    return best

