def _encode_gif_with_budget(raster: Raster, max_bytes: int) -> bytes:
    best = encode_gif(raster, max_colors=256)
    for colors in (256, 128, 64, 32, 16, 8):
        candidate = encode_gif(raster, max_colors=colors)
        best = candidate
        if len(candidate) <= max_bytes:
            return candidate

    longest = max(raster.width, raster.height)
    ratio = 0.9
    while ratio >= 0.35:
        target_longest = max(64, int(longest * ratio))
        working = fit_inside(raster, target_longest)
        for colors in (256, 128, 64, 32, 16, 8):
            candidate = encode_gif(working, max_colors=colors)
            best = candidate
            if len(candidate) <= max_bytes:
                return candidate
        ratio -= 0.1
    return best

