def _finalize_output(data: bytes, output_format: OutputFormat, strip_metadata: bool) -> bytes:
    if strip_metadata and output_format.extension == "jpg" and data.startswith(b"\xFF\xD8"):
        return strip_jpeg_metadata(data)
