def _encode_raster_with_budget(raster: Raster, output_format: OutputFormat, max_bytes: int) -> bytes:
    if output_format.extension == "png":
        return _encode_png_with_budget(raster, max_bytes)
    if output_format.extension == "jpg":
        return _encode_jpeg_with_budget(raster, max_bytes)
    if output_format.extension == "pdf":
        return _encode_pdf_with_budget(raster, max_bytes)
    if output_format.extension == "gif":
        return _encode_gif_with_budget(raster, max_bytes)
    if output_format.extension == "webp":
        return _encode_webp_with_budget(raster, max_bytes)
    if output_format.extension == "heic":
        raise ValueError(
            "HEIC encoding is not implemented in the native compressor engine. "
            "Choose JPG, PNG, or PDF."
        )
    raise ValueError("Unsupported output format.")
